namespace sv_1b92d70c0a624feb8a8c7da6f4e73f13.Services;

/// <summary>
/// Scoped service (per-circuit) that holds the currently selected warehouse
/// and notifies all subscribers when the selection changes.
/// </summary>
public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value) return;
            _currentWarehouseId = value;
            NotifyStateChanged();
        }
    }

    public string CurrentWarehouseName =>
        Warehouses.FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public static IReadOnlyList<Warehouse> Warehouses { get; } = new List<Warehouse>
    {
        new("WH-001", "Warehouse A — Main Distribution"),
        new("WH-002", "Warehouse B — Cold Storage"),
        new("WH-003", "Warehouse C — Overflow"),
        new("WH-004", "Warehouse D — Returns Processing")
    };

    public event Action? OnChange;

    private void NotifyStateChanged() => OnChange?.Invoke();
}

public record Warehouse(string Id, string Name);

namespace sv_1b92d70c0a624feb8a8c7da6f4e73f13.Services;

/// <summary>
/// Scoped service (per-circuit) that provides low-stock alert counts
/// and broadcasts changes to all subscribed components.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private Timer? _timer;
    private int _subscriberCount;
    private int _lastAlertCount;

    public int CurrentAlertCount => _lastAlertCount;

    /// <summary>
    /// Fired whenever new alert data arrives. All subscribed components
    /// (regardless of parent-child relationship) receive this notification.
    /// </summary>
    public event Func<Task>? OnAlertDataChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Call when a component wants polling to be active.
    /// Polling starts on the first subscriber and stops when all unsubscribe.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _timer = new Timer(PollCallback, null, TimeSpan.Zero, TimeSpan.FromSeconds(10));
        }
    }

    /// <summary>
    /// Call when a component no longer needs polling (e.g., leaving the page).
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _timer?.Dispose();
            _timer = null;
        }
    }

    private async void PollCallback(object? state)
    {
        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        _lastAlertCount = count;
        await NotifySubscribers();
    }

    private async void HandleWarehouseChanged()
    {
        // Immediately refresh when warehouse changes
        if (_timer is not null)
        {
            var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
            _lastAlertCount = count;
            await NotifySubscribers();
        }
    }

    private async Task NotifySubscribers()
    {
        if (OnAlertDataChanged is not null)
        {
            await OnAlertDataChanged.Invoke();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        _timer?.Dispose();
    }
}

