@rendermode InteractiveServer
@using sv_1b92d70c0a624feb8a8c7da6f4e73f13.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label for="warehouse-select"><strong>Current Warehouse:</strong></label>
    <select id="warehouse-select" class="form-select form-select-sm"
            @bind="SelectedWarehouseId">
        @foreach (var wh in WarehouseStateService.Warehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private string SelectedWarehouseId
    {
        get => WarehouseState.CurrentWarehouseId;
        set => WarehouseState.CurrentWarehouseId = value;
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@using sv_1b92d70c0a624feb8a8c7da6f4e73f13.Services
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="alert-badge" title="Low-stock alerts for current warehouse">
    @if (_alertCount > 0)
    {
        <span class="badge bg-danger">@_alertCount</span>
    }
    else
    {
        <span class="badge bg-success">0</span>
    }
</span>

@code {
    private int _alertCount;

    protected override void OnInitialized()
    {
        _alertCount = AlertService.CurrentAlertCount;
        AlertService.OnAlertDataChanged += HandleAlertDataChanged;
    }

    private async Task HandleAlertDataChanged()
    {
        _alertCount = AlertService.CurrentAlertCount;
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= HandleAlertDataChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_1b92d70c0a624feb8a8c7da6f4e73f13.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-header">
        <h5 class="mb-0">Current Site: @WarehouseState.CurrentWarehouseName</h5>
    </div>
    <div class="card-body">
        <p>Warehouse ID: <code>@WarehouseState.CurrentWarehouseId</code></p>

        <div class="d-flex align-items-center gap-3">
            <h4>
                Low-Stock Alerts:
                @if (_alertCount > 0)
                {
                    <span class="badge bg-danger fs-5">@_alertCount items</span>
                }
                else
                {
                    <span class="badge bg-success fs-5">All stocked</span>
                }
            </h4>
        </div>

        <p class="text-muted mt-2">
            <small>Polling every 10 seconds. Last updated: @_lastUpdated.ToString("HH:mm:ss")</small>
        </p>
    </div>
</div>

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">How This Works</h5>
